async function seed() {
  console.log(`Seeding ${INGREDIENTS.length} ingredients...`);
  const batchSize = 50;
  let total = 0;

  for (let i = 0; i < INGREDIENTS.length; i += batchSize) {
    // Ensure edible_portion always has a value (DB has NOT NULL constraint, default 1.0)
    const batch = INGREDIENTS.slice(i, i + batchSize).map(ing => ({
      ...ing,
      edible_portion: ing.edible_portion ?? 1.0,
    }));
    const { error } = await supabase
      .from('ingredients')
      .upsert(batch, { onConflict: 'name_en' });

    if (error) {
      console.error(`Batch ${Math.floor(i / batchSize) + 1} error:`, error.message);
    } else {
      total += batch.length;
      console.log(`Batch ${Math.floor(i / batchSize) + 1} done — ${total}/${INGREDIENTS.length} rows`);
    }
  }

  console.log(`\nSeed complete. ${total} ingredients upserted.`);
}

seed().catch(console.error);
